Consider the C++ code below that transposes a **2x3 matrix** into a **3x2 matrix**. What will be the output of this code?

```cpp
#include 
using namespace std;

int main() {
    // Declare and initialize a 2x3 matrix
    int matrix[2][3] = {{1, 2, 3}, {4, 5, 6}};

    // Declare a 3x2 matrix for the transpose
    int transposed[3][2];

    // Perform Matrix Transposition
    for (int i = 0; i < 2; i++) {  // Outer loop for rows
        for (int j = 0; j < 3; j++) {  // Inner loop for columns
            transposed[j][i] = matrix[i][j];  // Swap rows and columns
        }
    }

    // Print the transposed matrix
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 2; j++) {
            cout << transposed[i][j] << " ";
        }
        cout << endl;
    }

    return 0;
}
```

